    model: process.env.MINIMAX_MODEL ?? 'MiniMax-M2.1'
  },
  glm: {
    baseUrl: process.env.GLM_BASE_URL ?? 'https://open.bigmodel.cn/api/paas/v4',
    apiKey: process.env.GLM_API_KEY ?? '',
    model: process.env.GLM_MODEL ?? 'glm-4'
  }
}

function getProviderConfig(provider: ProviderKey): ProviderConfig {
  return providerConfigs[provider]
}

export async function requestChatCompletion(provider: ProviderKey, messages: ChatMessage[]) {
  const config = getProviderConfig(provider)
  if (!config.apiKey || !config.model) {
    throw new Error(`Missing API key or model for ${provider}`)
  }

  const response = await fetch(`${config.baseUrl}/chat/completions`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${config.apiKey}`,
      ...(config.headers ?? {})
    },
    body: JSON.stringify({
      model: config.model,
      messages,
      temperature: 0.6
    })
  })

  if (!response.ok) {
    const text = await response.text()
    throw new Error(`Request failed: ${response.status} ${response.statusText} ${text}`)
  }

  const data = await response.json()
  const content = data?.choices?.[0]?.message?.content
  if (!content) {
    throw new Error('Empty response from provider')
  }
  return content as string
}
